import { FC, useEffect, useMemo } from 'react';
import { connect } from 'react-redux';

import {
  Deck,
  ProductType,
  SeatAssignmentStatus,
  SeatSelection,
} from '@xivart/edge/types/postSale';
import { compose, Dispatch } from 'redux';
import { createStructuredSelector } from 'reselect';

import {
  changeSegmentIndex,
  changePassenger,
  changeSelections,
  changeDeck,
  submit,
  change,
  mount,
  resetStore,
  loadSelectionState,
} from './actions';
import { KEY } from './constants';
import epic from './epics';
import { reducer } from './reducer';
import {
  selectSegments,
  selectCurrentDeck,
  selectCurrentSegment,
  selectCurrentPassenger,
  selectPassengers,
  selectSeatSelections,
  selectIsSubmitting,
  selectIsSubmitErrored,
  selectCurrentSegmentIndex,
  selectIsActive,
  selectSeatSelectionsFromAssignments,
  selectPrevSeatSelections,
} from './selectors';
import {
  Props,
  OwnDispatch,
  SeatContainerProps,
  LoadSelectionStatePayload,
} from './types';
import { changeProductModalState } from '../PostSaleBookingProductsContainer/actions';
import injectEpic from '~app/domains/Common/helpers/store/injectEpic';
import injectReducer from '~app/domains/Common/helpers/store/injectReducer';
import { findFirstAvailablePassenger } from '~app/domains/PostSale/containers/SeatContainer/helper';

export const SeatContainer: FC<SeatContainerProps> = ({
  children,
  segments,
  passengers,
  isActive,
  isSubmitting,
  isSubmitErrored,
  currentSegment,
  currentDeck,
  currentPassenger,
  currentSegmentIndex,
  seatSelections,
  seatSelectionsFromAssignments,
  setCurrentSegmentIndex,
  setCurrentPassenger,
  setSeatSelections,
  setCurrentDeck,
  onSubmit,
  onActive,
  onClose,
  onChange,
  onMount,
  onResetStore,
  onLoadSelectionState,
  prevSeatSelections,
}) => {
  const { purchasedSeats, inCartSeats } = useMemo(
    () => ({
      purchasedSeats: seatSelectionsFromAssignments.filter(
        ({ status }) => status === SeatAssignmentStatus.PURCHASED,
      ),
      inCartSeats: seatSelectionsFromAssignments.filter(
        ({ status }) => status === SeatAssignmentStatus.IN_SHOPPING,
      ),
    }),
    [seatSelectionsFromAssignments],
  );

  useEffect(() => {
    if (!currentSegment) {
      setCurrentSegmentIndex(
        segments.findIndex((segment) => segment.decks.length > 0),
      );
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  useEffect(() => {
    if (currentSegment) {
      const firstAvailablePassenger = findFirstAvailablePassenger(
        currentSegment,
        purchasedSeats,
      );

      setCurrentPassenger(firstAvailablePassenger);
    }
  }, [currentSegment, purchasedSeats, setCurrentPassenger]);

  useEffect(() => {
    if (currentSegment) {
      setCurrentDeck(currentSegment.decks[0]);
    }
  }, [currentSegment, setCurrentDeck]);

  useEffect(() => {
    if (inCartSeats.length) {
      onMount(inCartSeats);
    } else {
      onMount([]);
    }

    return onResetStore;
  }, [onMount, inCartSeats, onResetStore]);

  const handleChange = () => onChange(seatSelections);

  const handleSubmit = () => onSubmit(seatSelections);

  return children({
    segments,
    passengers,
    currentDeck,
    isSubmitting,
    currentSegment,
    seatSelections,
    purchasedSeats,
    isSubmitErrored,
    currentPassenger,
    currentSegmentIndex,
    isActive,
    setCurrentSegmentIndex,
    setCurrentPassenger,
    setSeatSelections,
    setCurrentDeck,
    onActive,
    onClose,
    onSubmit: handleSubmit,
    onChange: handleChange,
    onLoadSelectionState,
    prevSeatSelections,
  });
};

const mapStateToProps = createStructuredSelector({
  passengers: selectPassengers,
  segments: selectSegments,
  currentPassenger: selectCurrentPassenger,
  currentSegment: selectCurrentSegment,
  currentDeck: selectCurrentDeck,
  currentSegmentIndex: selectCurrentSegmentIndex,
  seatSelections: selectSeatSelections,
  isSubmitting: selectIsSubmitting,
  isSubmitErrored: selectIsSubmitErrored,
  isActive: selectIsActive,
  seatSelectionsFromAssignments: selectSeatSelectionsFromAssignments,
  prevSeatSelections: selectPrevSeatSelections,
});

export const mapDispatchToProps = (dispatch: Dispatch): OwnDispatch => ({
  setCurrentPassenger: (passenger) => {
    dispatch(changePassenger(passenger));
  },
  setCurrentSegmentIndex: (index?: number) => {
    dispatch(changeSegmentIndex(index));
  },
  onMount: (selections: SeatSelection[]) => {
    dispatch(mount(selections));
  },
  setSeatSelections: (selections: SeatSelection[]) =>
    dispatch(changeSelections(selections)),
  setCurrentDeck: (deck: Deck) => {
    dispatch(changeDeck(deck));
  },
  onChange: (payload: SeatSelection[]) => {
    dispatch(change(payload));
  },
  onSubmit: (payload: SeatSelection[]) => {
    dispatch(submit(payload));
  },
  onActive: () =>
    dispatch(
      changeProductModalState({
        productType: ProductType.Seat,
        status: true,
      }),
    ),
  onLoadSelectionState: (payload) => dispatch(loadSelectionState(payload)),
  onClose: (payload: LoadSelectionStatePayload) => {
    dispatch(
      changeProductModalState({
        productType: ProductType.Seat,
        status: false,
      }),
    );
    dispatch(loadSelectionState(payload));
  },
  onResetStore: () => dispatch(resetStore()),
});

const withConnect = connect(mapStateToProps, mapDispatchToProps);

const withReducer = injectReducer<Props>({ key: KEY, reducer });

const withEpic = injectEpic<Props>({ key: KEY, epic });

export const SeatContainerWithStore = compose(
  withEpic,
  withReducer,
  withConnect,
)(SeatContainer);

