    if (bookingDetail?.passengers) {
      const pnrLegSegmentMapping =
        bookingDetail.legs!.reduce<PnrLegSegmentMapping[]>((acc, leg) => {
          if (!leg || !leg.pnrId) return acc;

          const exist = acc.find((item) => item.pnrId === leg.pnrId);

          const segments: BookingSegment[] = Array.isArray(leg.segments)
            ? leg.segments
            : [];

          const segmentNumbers = segments
            .map((seg) => seg && seg.segmentNumber)
