import { selectSeatSelectionsFromAssignments } from '../selectSeatSelectionsFromAssignments';
import {
  passengerAdult2,
  passengerChild,
} from '~app/internal/apiMocks/postSale/basicObjects/PassengersMock';
import { segmentsMock } from '~app/internal/apiMocks/postSale/basicObjects/SegmentsMock';
import { pnrId1 } from '~app/internal/apiMocks/postSale/basicObjects/constants';

describe('selectSeatSelectionsFromAssignments', () => {
  const { resultFunc } = selectSeatSelectionsFromAssignments;

  it('should select no data', () => {
    const result = resultFunc({ segments: [segmentsMock[0]] }, undefined);

    expect(result).toStrictEqual([]);
  });

  it('should return [] when it has no seat data', () => {
    const result = resultFunc(undefined, undefined);

    expect(result).toStrictEqual([]);
  });

  it('should return [] when it has no segment data', () => {
    const result = resultFunc({ segments: [] }, undefined);

    expect(result).toStrictEqual([]);
  });

  it('should return [] when booking is not matched', () => {
    const result = resultFunc({ segments: [segmentsMock[0]] }, undefined);

    expect(result).toStrictEqual([]);
  });

  it('should return [] for this pax if it cannot match the booking passenger', () => {
    const result = resultFunc({ segments: [segmentsMock[0]] }, {
      pnrId: pnrId1,
      passengers: [],
    } as any);

    expect(result).toStrictEqual([]);
  });

  it('should handle bookingDetail branch when bookingDetail is provided with matching passengers', () => {
    const mockBookingDetail = {
      pnrId: pnrId1,
      passengers: [
        {
          id: passengerAdult2.passengerIndex,
          firstName: passengerAdult2.firstName,
          lastName: passengerAdult2.lastName,
        },
        {
          id: passengerChild.passengerIndex,
          firstName: passengerChild.firstName,
          lastName: passengerChild.lastName,
        },
      ],
    } as any;

    const result = resultFunc(
      { segments: [segmentsMock[0]] },
      mockBookingDetail,
    );

    expect(result).toHaveLength(2);
    expect(result[0]).toMatchObject({
      passengerIndex: passengerAdult2.passengerIndex,
      pnrId: pnrId1,
      firstName: passengerAdult2.firstName,
      lastName: passengerAdult2.lastName,
    });
  });

  it('should return [] when bookingDetail is provided but passenger not found', () => {
    const result = resultFunc({ segments: [segmentsMock[0]] }, {
      pnrId: pnrId1,
      passengers: [],
    } as any);

    expect(result).toStrictEqual([]);
  });
});

