import { Passenger } from '@xivart/edge/types/account';
import { BaggageDefaultStatus } from '@xivart/edge/types/baggage';
import { PassengerTypes } from '@xivart/edge/types/customer';
import {
  BaggageProduct,
  ProductAvailability,
  PassengerBaggageProduct,
} from '@xivart/edge/types/postSale';

import { BaggagePassenger, PnrLegSegmentMapping } from '../types';

export const baggagePassengersTransform = (
  passengers: readonly Passenger[],
  baggageProduct: readonly BaggageProduct[],
  pnrLegSegmentMapping: PnrLegSegmentMapping[],
): BaggagePassenger[] =>
  passengers.map((passenger) => {
    const baggageProducts: PassengerBaggageProduct[] = [];

    pnrLegSegmentMapping.forEach(
      ({ pnrId, segmentNumbers, segmentIdentifiers }) => {
        let availability: ProductAvailability;
        let baggageOptions: BaggageProduct[] = [];
        const baggageProductList = baggageProduct.filter(
          (bag) => pnrId === bag.pnrId,
        );

        const baggageForAdult = baggageProductList.filter((bag) =>
          bag.availablePassengerTypes.includes(PassengerTypes.Adult),
        );
        const baggageForChild = baggageProductList.filter((bag) =>
          bag.availablePassengerTypes.includes(PassengerTypes.Child),
        );

        if (baggageProductList.length === 0) {
          availability = ProductAvailability.NotAvailable;
        } else {
          const pnrPassengerBaggage = passenger.baggage.find((item) =>
            segmentNumbers.includes(item.segmentNumber),
          );

          const included =
            pnrPassengerBaggage?.defaultBaggage.status ===
            BaggageDefaultStatus.Included;

          const purchased = pnrPassengerBaggage?.baggage.some(
            (bagProduct) =>
              bagProduct.segmentIdentifier &&
              segmentIdentifiers.includes(bagProduct.segmentIdentifier),
          );

          availability =
            included || purchased
              ? ProductAvailability.Purchased
              : ProductAvailability.Available;
        }

        if (passenger.passengerType === PassengerTypes.Adult) {
          baggageOptions = baggageForAdult;
        }
        if (passenger.passengerType === PassengerTypes.Child) {
          baggageOptions = baggageForChild;
        }

        baggageProducts.push({
          baggageAvailability: availability,
          baggageOptions,
          pnrId,
        });
      },
    );

    return {
      ...passenger,
      passengerIndex: passenger.id,
      seat: [],
      baggage: [],
      baggageFlat: passenger.baggage,
      baggageProducts,
    };

