26	  const bookingPassengersMap = new Map(
27	    passengersList.map((passenger) => [
28	      'id' in passenger ? passenger.id : passenger.passengerIndex,
29	      passenger,
30	    ]),
31	  );
32	
33	  const segments: SeatSegment[] = bookingSegments.map((bookingSegment) => {
34	    const seatSegment: Segment | undefined = responseSegments.find(
35	      (segment) => segment.segmentIdentifier === bookingSegment.identifier,
